def rabin_karp(text, pattern):
    n, m = len(text), len(pattern)
    if m > n:
        return -1
    BASE, MOD = 131, 10**9 + 7

    # Compute pattern hash + initial window hash + BASE^(m-1)
    p_hash = t_hash = 0
    power = 1
    for i in range(m):
        p_hash = (p_hash * BASE + ord(pattern[i])) % MOD
        t_hash = (t_hash * BASE + ord(text[i]))    % MOD
        if i < m - 1:
            power = (power * BASE) % MOD

    if p_hash == t_hash and text[:m] == pattern:
        return 0

    for i in range(1, n - m + 1):
        # Roll: remove leftmost char, add new rightmost char
        t_hash = (t_hash - ord(text[i - 1]) * power % MOD + MOD) % MOD
        t_hash = ___________
        if t_hash == p_hash and text[i:i + m] == pattern:
            return i
    return -1
